const TRANSLATIONS={zh:{pageTitle:"MFTI — 「男娘」人格测试",metaDescription:"MFTI — 一个「男娘」人格测试，纯属娱乐。39道题目，10个维度评分，测出你是哪种生物。",subtitle:"Male to Female Type Indicator",description:"一个「男娘」人格测试，纯属娱乐。<br>39道题目，10个维度评分。<br>测出你是哪种生物。",statLabels:["人格类型","道测试题","个维度","分钟完成"],startBtn:"开始测试 →",showResultBtn:"查看上次结果",disclaimerNote:"点击前需阅读并同意免责声明",disclaimerTitle:"在进入测试前，请先看完这段话",disclaimerText:["🎭 <strong>本测试纯属娱乐，整活性质，请不要认真。</strong>","😂 测试内容包含大量夸张描述、辛辣嘲讽和无厘头选项，如果你容易被冒犯，建议关掉这个页面去看点正经的东西。","🔬 虽然题目设计参考了若干心理学框架，但我们不是心理学家，你也不需要因为测试结果对自己做任何定义。","🌈 测试结果不代表任何价值判断，所有人格类型都是平等的，包括那些听起来在被嘲讽的类型——我们在嘲讽的是人类共有的荒谬，不是针对任何个体。","🎯 如果测试结果让你感到困惑或情绪波动，这可能是因为你需要和真正的心理咨询师聊聊，而不是再做一遍测试。","💫 <strong>总之：轻松做，别当真，笑一笑，往前走。</strong>"],disagreeBtn:"不同意，返回",agreeBtn:"我已阅读，同意进入",remaining:"还剩",questionsLeft:"题",prevBtn:"← 上一题",nextBtn:"下一题 →",submitBtn:"查看结果 ✨",calcTexts:["正在分析您的心理画像...","校准粉色梦境指数...","检测深柜深度...","评估社牛系数...","正在输出人格报告..."],calcSubtext:"AI正在努力研究你这个复杂个体...",portraitTitle:"🔍 人格画像",dimensionsTitle:"📊 你的十维度评分",similarTitle:"🔮 你与以下类型也有相似之处",shareBtn:"📤 分享结果",retakeBtn:"🔄 再测一次",allPersonalitiesBtn:"👥 查看所有人格",footerNote:'MFTI · 「男娘」人格测试 · 结果仅供娱乐参考<br>如有雷同，纯属你也是这类人 <img src="images/sakura.svg?v=1.0.2" class="footer-sakura" alt="🌸">',shareText:'我是MFTI的「{name}」({code}) {emoji}\n"{subtitle}"\n👉 来测测你的专属类型：https://mfti.hey.run',copiedToast:"结果已复制到剪贴板 📋",copyFailedToast:"请手动截图分享哦~",unansweredToast:"还有 {count} 道题没有作答哦 👀",allPersonalitiesTitle:"👥 所有16种MFTI人格",allPersonalitiesSubtitle:"探索不同的人格类型，找到最符合你的特质",backBtn:"← 返回首页",footerAuthor:"作者：",dimensions:{PR:{name:"粉色梦境指数",low:"现实派",high:"梦幻派",balanced:"均衡型"},SH:{name:"社交活跃度",low:"宅家精灵",high:"社交蝴蝶",balanced:"均衡型"},AI:{name:"颜值焦虑度",low:"心态平和",high:"颜值焦虑",balanced:"均衡型"},EW:{name:"公开度",low:"深柜居民",high:"公开出柜",balanced:"均衡型"},CF:{name:"自律指数",low:"佛系随缘",high:"严格自律",balanced:"均衡型"},DK:{name:"社群归属感",low:"独行侠",high:"群体依附",balanced:"均衡型"},TN:{name:"理性分析度",low:"纯靠直觉",high:"理论狂魔",balanced:"均衡型"},MB:{name:"物质投入度",low:"佛系省钱",high:"钱不是问题",balanced:"均衡型"},GL:{name:"表达一致性",low:"看心情派",high:"全天候在线",balanced:"均衡型"},XZ:{name:"未来规划度",low:"随遇而安",high:"五年计划党",balanced:"均衡型"}},tags:{"社交蝴蝶":"Social Butterfly","梦幻泡泡":"Dream Bubble","伪社牛":"Fake Social Butterfly","深夜发疯":"Late Night Spiraling","哲学女孩":"Philosophy Girl","人格分裂 er":"Split Personality","人格分裂er":"Split Personality","双面人生":"Double Life","神秘人":"Mysterious Person","自给自足":"Self-sufficient","箱子里的宇宙":"Universe in a Box","分析过度":"Over-analyzing","哲学系":"Philosophy Major","长文预警":"Long Text Warning","到底出不出来":"To Be Or Not To Be Out","宅家精灵":"Home Spirit","孤独美学家":"Lonely Aesthete","镜前在意":"Mirror Conscious","神秘系":"Mysterious Type","镜子是灵魂":"Mirror Is the Soul","深柜深处":"Deep in Closet","不确定":"Uncertain","漂浮态":"Floating State","等待触发":"Waiting for Trigger","务实主义":"Pragmatist","学术控":"Academic Nerd","数据怪":"Data Freak","研究自己":"Self-Researcher","懒得解释":"Too Lazy to Explain","低调清醒":"Low-key Sober","随便吧":"Whatever","最不焦虑的人":"Least Anxious Person","智识孤独者":"Intellectual Loner","理论宇宙":"Theory Universe","自建体系":"Self-built System","发长文没人看":"Long Posts No One Reads","执行力恐怖":"Terrifying Execution","硬核计划派":"Hardcore Planner","焦虑转化器":"Anxiety Transformer","别拦我":"Don't Stop Me","出柜中的哲学家":"Philosopher in Coming Out","佛系进度":"Buddha-like Progress","修炼感":"Cultivation Vibe","别催":"Don't Rush Me","务实派":"Pragmatic One","颜值在意":"Appearance Conscious","绽放者":"Blossomer","适应力强":"Highly Adaptable","谨慎者":"Cautious One","平衡者":"Balancer","灵活应变":"Quick to Adapt","爱美之人":"Beauty Lover","私密绽放":"Private Bloomer","温柔细腻":"Gentle and Delicate","清醒者":"Sober Soul","智慧担当":"Wisdom Bearer","勇气可嘉":"Courageous One","保护者":"Protector","平衡大师":"Balance Master","生活艺术家":"Life Artist","享受当下":"Live in the Moment","好奇宝宝":"Curious Soul","探索者":"Explorer","思考者":"Thinker","观察者":"Observer"}},en:{pageTitle:"MFTI — Male to Female Type Indicator",metaDescription:"MFTI — A playful 'femboy' personality test. 39 questions, 10 dimensions, find out what type you are.",subtitle:"Male to Female Type Indicator",description:"A playful 'femboy' personality test, just for fun.<br>39 questions, 10 dimensions.<br>Find out what type you are.",statLabels:["Personality Types","Questions","Dimensions","Minutes to Complete"],startBtn:"Start Test →",showResultBtn:"View Previous Result",disclaimerNote:"Read and agree to disclaimer before starting",disclaimerTitle:"Before you start, please read this",disclaimerText:["🎭 <strong>This test is purely for entertainment purposes. Don't take it seriously.</strong>","😂 The test contains lots of exaggeration, sarcasm, and absurd options. If you're easily offended, maybe go read something more serious.","🔬 While the questions reference some psychological frameworks, we're not psychologists, and you shouldn't define yourself based on the results.","🌈 Results don't represent any value judgment. All personality types are equal, including those that sound like they're being mocked—we're mocking the absurdity we all share, not any individual.","🎯 If the results make you feel confused or emotional, maybe talk to a real therapist instead of taking the test again.","💫 <strong>In short: Take it easy, don't take it seriously, laugh, and move on.</strong>"],disagreeBtn:"Disagree, go back",agreeBtn:"I've read it, let's go",remaining:"Remaining",questionsLeft:"questions",prevBtn:"← Previous",nextBtn:"Next →",submitBtn:"See Results ✨",calcTexts:["Analyzing your psychological profile...","Calibrating pink dream index...","Detecting closet depth...","Assessing social butterfly coefficient...","Generating personality report..."],calcSubtext:"AI is working hard to understand your complex self...",portraitTitle:"🔍 Personality Portrait",dimensionsTitle:"📊 Your 10 Dimension Scores",similarTitle:"🔮 You also have similarities with these types",shareBtn:"📤 Share Result",retakeBtn:"🔄 Take Again",allPersonalitiesBtn:"👥 View All Personalities",footerNote:'MFTI · Personality Test · For entertainment purposes only<br>If it fits, it fits <img src="images/sakura.svg?v=1.0.2" class="footer-sakura" alt="🌸">',shareText:'I\'m a MFTI "{name}" ({code}) {emoji}\n"{subtitle}"\n👉 Discover your type: https://mfti.hey.run',copiedToast:"Result copied to clipboard 📋",copyFailedToast:"Please take a screenshot to share~",unansweredToast:"You still have {count} questions to answer 👀",allPersonalitiesTitle:"👥 All 16 MFTI Personalities",allPersonalitiesSubtitle:"Explore different personality types and find your best fit",backBtn:"← Back to Home",footerAuthor:"By ",dimensions:{PR:{name:"Pink Dream Index",low:"Realist",high:"Dreamer",balanced:"Balanced"},SH:{name:"Social Activity",low:"Homebody",high:"Social Butterfly",balanced:"Balanced"},AI:{name:"Appearance Anxiety",low:"Chill",high:"Anxious",balanced:"Balanced"},EW:{name:"Openness Level",low:"Deep Closet",high:"Fully Out",balanced:"Balanced"},CF:{name:"Self-Discipline",low:"Go with Flow",high:"Strictly Planned",balanced:"Balanced"},DK:{name:"Community Belonging",low:"Loner",high:"Community Dependent",balanced:"Balanced"},TN:{name:"Analytical Level",low:"Intuition Driven",high:"Theory Maniac",balanced:"Balanced"},MB:{name:"Material Investment",low:"Budget Conscious",high:"Money No Object",balanced:"Balanced"},GL:{name:"Expression Consistency",low:"Mood Dependent",high:"Always On",balanced:"Balanced"},XZ:{name:"Future Planning",low:"Winging It",high:"5-Year Planner",balanced:"Balanced"}}}};"undefined"!=typeof module&&(module.exports={TRANSLATIONS:TRANSLATIONS});